SELECT COUNT(*) AS total_videos
FROM video_files
WHERE file_size > 50;

SELECT file_type, COUNT(*) AS file_type_count
FROM video_files
GROUP BY file_type;

SELECT interaction_type, interaction_date
FROM user_interactions
WHERE interaction_date = (
  SELECT MAX(interaction_date) 
  FROM user_interactions
);

SELECT AVG(interaction_duration) AS average_interaction_duration
FROM user_interactions
WHERE user_id = 0 AND interaction_type = 'view';

SELECT COUNT(*) AS detection_count
FROM activity_detections
WHERE confidence_score > 0.8;
